from collections import deque

def main():
    n, d = map(int, sys.stdin.readline().split())
    coords = [tuple(map(int, sys.stdin.readline().split())) for _ in range(n)]
    adj = [[] for _ in range(n)]
    d_sq = d * d

    for i in range(n):
        xi, yi = coords[i]
        for j in range(n):
            if i == j:
                continue
            xj, yj = coords[j]
            dx = xi - xj
            dy = yi - yj
            if dx * dx + dy * dy <= d_sq:
                adj[i].append(j)

    visited = [False] * n
    q = deque()
    q.append(0)
    visited[0] = True

    while q:
        current = q.popleft()
        for neighbor in adj[current]:
            if not visited[neighbor]:
                visited[neighbor] = True
                q.append(neighbor)

    for i in range(n):
        print("Yes" if visited[i] else "No")

