    input = sys.stdin.read().split()
    N = int(input[0])
    S = input[1] if len(input) > 1 else ""
    current_str = list(S)

    while True:
        found = False
        stack = []
        pairs = []
        for i in range(len(current_str)):
            if current_str[i] == '(':
                stack.append(i)
            elif current_str[i] == ')':
                if stack:
                    j = stack.pop()
                    pairs.append((j, i))

        # Compute prefix array
        prefix = [0] * len(current_str)
        for k in range(len(current_str)):
            prefix[k] = prefix[k-1] + (1 if current_str[k] in '()' else 0)

        # Check for valid pairs
        to_remove = set()
        for (i, j) in pairs:
            if j - i == 1:
                to_remove.add(i)
                to_remove.add(j)
            else:
                if j - 1 >= 0:
                    count = prefix[j-1] - prefix[i]
                    if count == 0:
                        to_remove.add(i)
                        to_remove.add(j)

        if to_remove:
            found = True
            # Remove indices in reverse order to avoid index shifting issues
            indices = sorted(to_remove, reverse=True)
            for idx in indices:
                del current_str[idx]
        else:
            break

    print(''.join(current_str))

