import functools

def main():
    n = int(sys.stdin.readline())
    people = []
    for i in range(n):
        a, b = map(int, sys.stdin.readline().split())
        people.append((a, b, i + 1))

    def compare(a, b):
        aA, aB, aIdx = a
        bA, bB, bIdx = b
        left = aA * (bA + bB)
        right = bA * (aA + aB)
        if left > right:
            return -1
        elif left < right:
            return 1
        else:
            if aIdx < bIdx:
                return -1
            else:
                return 1

    people_sorted = sorted(people, key=functools.cmp_to_key(compare))
    result = [str(p[2]) for p in people_sorted]
    print(' '.join(result))

