import sys
from collections import deque

def main():
    input = sys.stdin.read().split()
    ptr = 0
    N = int(input[ptr])
    ptr += 1

    prereq = [[] for _ in range(N + 1)]
    for i in range(1, N + 1):
        C_i = int(input[ptr])
        ptr += 1
        for _ in range(C_i):
            p = int(input[ptr])
            ptr += 1
            prereq[i].append(p)

    # Build adjacency list for BFS
    adj = [[] for _ in range(N + 1)]
    for i in range(1, N + 1):
        for p in prereq[i]:
            adj[i].append(p)

    # BFS to find all nodes reachable from 1 (including 1)
    visited = set()
    q = deque([1])
    visited.add(1)
    while q:
        u = q.popleft()
        for v in adj[u]:
            if v not in visited:
                visited.add(v)
                q.append(v)

    # Build in_S (exclude 1)
    in_S = [False] * (N + 1)
    for node in visited:
        if node != 1:
            in_S[node] = True

    # Build dep_adj and in_degree for nodes in S
    dep_adj = [[] for _ in range(N + 1)]
    in_degree = [0] * (N + 1)
    for i in range(1, N + 1):
        if in_S[i]:
            for p in prereq[i]:
                if in_S[p]:
                    dep_adj[p].append(i)
                    in_degree[i] += 1

    # Topological sort
    q = deque()
    for i in range(1, N + 1):
        if in_S[i] and in_degree[i] == 0:
            q.append(i)

    result = []
    while q:
        u = q.popleft()
        result.append(u)
        for v in dep_adj[u]:
            if in_S[v]:
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    q.append(v)

    print(' '.join(map(str, result)))

