import sys

def main():
    N, M = map(int, sys.stdin.readline().split())
    L = list(map(int, sys.stdin.readline().split()))

    def is_possible(W):
        lines = 1
        current = 0
        for word in L:
            if current == 0:
                if word > W:
                    return False
                current = word
            else:
                if current + 1 + word > W:
                    lines += 1
                    if lines > M:
                        return False
                    current = word
                else:
                    current += 1 + word
        return True

    low = max(L)
    high = sum(L) + (N - 1)
    ans = high

    while low <= high:
        mid = (low + high) // 2
        if is_possible(mid):
            ans = mid
            high = mid - 1
        else:
            low = mid + 1

    print(ans)

