    idx += 1
    results = []
    for _ in range(T):
        N = int(input[idx])
        X = int(input[idx+1])
        K = int(input[idx+2])
        idx += 3
        if K == 0:
            results.append(1)
            continue
        total = 0
        max_a = min(K, 60)
        for a in range(0, max_a + 1):
            if a == 0:
                d = K
                if d < 0:
                    continue
                if d == 0:
                    total += 1
                else:
                    depth = d
                    if depth > 60:
                        pass
                    else:
                        low = X * (1 << depth)
                        if low > N:
                            count = 0
                        else:
                            high = low + ((1 << depth) - 1)
                            if high > N:
                                count = N - low + 1
                            else:
                                count = (1 << depth)
                        total += count
            else:
                if X < (1 << a):
                    continue
                Y = X >> a
                C = X >> (a - 1)
                S = C ^ 1
                d = K - a
                if d < 0:
                    continue
                if d == 0:
                    total += 1
                else:
                    depth_sub = d - 1
                    if depth_sub > 60:
                        pass
                    else:
                        low = S * (1 << depth_sub)
                        if low > N:
                            count = 0
                        else:
                            high = low + ((1 << depth_sub) - 1)
                            if high > N:
                                count = N - low + 1
                            else:
                                count = (1 << depth_sub)
                        total += count
        results.append(total)
