import sys

def main():
    data = sys.stdin.read().split()
    N = int(data[0])
    T = data[1]
    S_list = data[2:2 + N]

    res = []

    for idx, S in enumerate(S_list, 1):
        len_S = len(S)
        len_T = len(T)
        valid = False

        if len_S == len_T:
            if S == T:
                valid = True
            else:
                diff = 0
                for a, b in zip(S, T):
                    if a != b:
                        diff += 1
                        if diff > 1:
                            break
                valid = (diff <= 1)
        elif len_S == len_T + 1:
            # Check if T can be obtained by deleting one character from S
            i = 0
            j = 0
            delete_count = 0
            while i < len_T and j < len_S:
                if T[i] == S[j]:
                    i += 1
                    j += 1
                else:
                    j += 1
                    delete_count += 1
                    if delete_count > 1:
                        break
            valid = (i == len_T)
        elif len_S == len_T - 1:
            # Check if T can be obtained by inserting one character into S
            # which is equivalent to checking if S can be obtained by deleting one from T
            i = 0
            j = 0
            delete_count = 0
            while i < len_S and j < len_T:
                if S[i] == T[j]:
                    i += 1
                    j += 1
                else:
                    j += 1
                    delete_count += 1
                    if delete_count > 1:
                        break
            valid = (i == len_S)
        else:
            valid = False

        if valid:
            res.append(idx)

    print(len(res))
    if res:
        print(' '.join(map(str, res)))

if __name__ == '__main__':
    main()
